module top_module(
    input clk,
    input rst,
    output reg [2:0] out
);reg [2:0] unused_count;

always @(posedge clk) begin
    if (rst) begin
        unused_count <= 3'b0;
    end else if (unused_count == 3'b111) begin
        unused_count <= 3'b0;
    end else begin
        unused_count <= unused_count + 1;
    end
end

assign out = unused_count;

endmodule
